def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    n = len(bins)
    positive_bins = bins[bins > 0]
    avg_capacity = np.mean(positive_bins) if positive_bins.size > 0 else 1
    variance = np.var(positive_bins) if positive_bins.size > 0 else 0.1
    median_capacity = np.median(positive_bins) if positive_bins.size > 0 else 1
    skewness = np.mean((positive_bins - avg_capacity) ** 3) / (variance ** 1.5 + 1e-9) if variance > 0 else 0
    for i in range(n):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        if item > capacity:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        score = 0.0
        if ratio == 1:
            score = 0.0
        elif ratio > 0.9:
            score = ((1 - ratio) ** 7) * 1.5 + 0.3
        elif 0.7 < ratio <= 0.9:
            score = np.log(1 + np.exp(-ratio * 20)) + 0.1
        elif 0.4 < ratio <= 0.7:
            temp = 0.0
            for k in range(1, 12):
                sign = 1 if k % 2 == 1 else -1
                temp += sign * (ratio ** (k + 3)) / (k ** 1.2)
            score = abs(temp) + 0.12
        else:
            temp = 0.0
            for p in range(1, 15):
                weight = 1 / (p ** 1.4)
                sign = -1 if p % 2 == 0 else 1
                temp += sign * (ratio ** (p + 2)) * weight
            score = abs(temp) + 0.14
        neighbors_influence = 0.0
        neighbors_weights_sum = 0.0
        for offset in range(1, 10):
            neighbors = []
            if i - offset >= 0:
                neighbors.append(bins[i - offset])
            if i + offset < n:
                neighbors.append(bins[i + offset])
            for neighbor_capacity in neighbors:
                if neighbor_capacity > 0:
                    diff = abs(capacity - neighbor_capacity)
                    norm_diff = diff / max(capacity, neighbor_capacity)
                    weight = 1 / (offset ** 2)
                    influence = norm_diff * weight
                    if neighbor_capacity > avg_capacity + 1.5 * variance:
                        influence *= 1.15
                    elif neighbor_capacity < avg_capacity - 1.5 * variance:
                        influence *= 0.85
                    if skewness > 0.5 and neighbor_capacity < median_capacity:
                        influence *= 0.9
                    elif skewness < -0.5 and neighbor_capacity > median_capacity:
                        influence *= 1.1
                    neighbors_influence += influence
                    neighbors_weights_sum += weight
        if neighbors_weights_sum > 0:
            neighbors_influence /= neighbors_weights_sum
        cap_factor = (capacity ** 0.75) + (avg_capacity ** 0.25)
        if cap_factor == 0:
            cap_factor = 1
        penalty = 0
        if capacity < item:
            penalty = ((item - capacity) ** 3) * 0.5
        elif capacity > item * 2.5:
            penalty = 0.07
        if i % 5 == 0:
            score *= 0.85
            neighbors_influence *= 1.15
            penalty *= 1.2
        elif i % 3 == 0:
            score *= 1.05
            neighbors_influence *= 0.85
        elif i % 7 == 0:
            score *= 1.2
            neighbors_influence *= 0.9
            penalty *= 0.9
        else:
            score *= 0.92
        priority = score + neighbors_influence / cap_factor + penalty
        if priority < 0:
            priority = 0
        priorities[i] = priority
    finite = priorities[np.isfinite(priorities)]
    if finite.size == 0:
        return priorities
    max_finite = np.max(finite)
    for i in range(n):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_finite * 7
    for i in range(n):
        if priorities[i] > max_finite * 3 and bins[i] < item * 0.5:
            priorities[i] += 0.1 * (bins[i] / (avg_capacity + 1e-9))
    return priorities
